private void inlineAliases(GlobalNamespace namespace) {
  Deque<Name> workList = new ArrayDeque<Name>(namespace.getNameForest());
  while (!workList.isEmpty()) {
    Name name = workList.pop();

    if (name.type == Name.Type.GET || name.type == Name.Type.SET) {
      continue;
    }

    if (name.globalSets == 1 && name.localSets == 0 &&
        name.aliasingGets > 0 && canInline(name)) {
      List<Ref> refs = Lists.newArrayList(name.getRefs());
      for (Ref ref : refs) {
        if (ref.type == Type.ALIASING_GET && ref.scope.isLocal()) {
          if (inlineAliasIfPossible(ref, namespace)) {
            name.removeRef(ref);
          }
        }
      }
    }

    if ((name.type == Name.Type.OBJECTLIT ||
         name.type == Name.Type.FUNCTION) &&
        name.aliasingGets == 0 && name.props != null) {
      workList.addAll(name.props);
    }
  }
}

private boolean canInline(Name name) {
  // Checks for special cases and other conditions where inlining is not appropriate
  String baseName = name.getBaseName();
  return !"arguments".equals(baseName) && !isBuiltInGlobal(baseName);
}

private boolean isBuiltInGlobal(String name) {
  // List of known global names that should not be inlined
  return "this".equals(name) || "window".equals(name);
}
